        <Route path="/sugarMonitor" element={<SugarMonitor />} />
        <Route path="/emotionMonitor" element={<EmotionMonitor />} />
        <Route path="/report" element={<WeeklyReport />} />
        <Route path="/foodMonitor" element={<FoodTracking />} />
        <Route path="/exerciseMonitor" element={<SelectExercise />} />
        <Route path='/recommendation' element={<Recommendation />} />
        <Route path='/weeklyreport' element={<WeeklyReport />} />
        <Route path='/profile' element={<Profile />} />
      </Routes>
    </div>
  );
}

export default App;
